add("Cognitive Diversity and Innovation","認知的多様性とイノベーション","チーム・組織メンバーの思考スタイル、問題解決アプローチ、知識基盤の多様性がイノベーション・パフォーマンスに与える影響の分析。認知的多様性は問題解決の解空間を拡大するが、調整コストも増大させる。","認知的多様性のイノベーション促進メカニズム。","組織学習",2004,"organizational","認知的多様性による創造的問題解決",["Scott Page"],["Page (2007) The Difference"],"","認知的多様性,創造的問題解決,チーム構成","cognitive diversity, creative problem solving, team composition")
add("Knowledge Integration in Cross-Functional Teams","機能横断チームにおける知識統合","マーケティング、エンジニアリング、製造等の異なる機能部門の専門知識を新製品開発チーム内で統合するメカニズム。共有言語の開発、境界オブジェクト、T型スキル人材等が統合を促進する。","機能横断的な専門知識の統合メカニズム。","知識マネジメント",1997,"organizational","異領域知識の統合プロセス",["Kathleen Eisenhardt","Behnam Tabrizi"],["Eisenhardt & Tabrizi (1995) Accelerating Adaptive Processes"],"","機能横断チーム,知識統合,共有言語","cross-functional team, knowledge integration, shared language")
add("Organizational Learning from Failure","失敗からの組織学習","プロジェクトの失敗、事故、ミス等の否定的経験から組織が体系的に学習するメカニズム。心理的安全性（Edmondson）が失敗からの学習を促進する組織条件として重要。","失敗経験からの組織的学習のメカニズムと条件。","組織学習",1999,"organizational","失敗からの教訓抽出と適用",["Amy Edmondson"],["Edmondson (1999) Psychological Safety and Learning Behavior"],"","失敗学習,心理的安全性,教訓","learning from failure, psychological safety, lessons, error management")
add("Psychological Safety","心理的安全性","対人関係のリスクを取っても安全だというチームの共有信念。Edmondson（1999年）が概念化し、心理的安全性が高いチームでは失敗の報告、質問、アイデア提案等の学習行動が促進される。","チーム学習を促進する心理的条件。","組織学習",1999,"organizational","安全な環境での学習行動促進",["Amy Edmondson"],["Edmondson (1999) Psychological Safety and Learning Behavior"],"","心理的安全性,チーム学習,リスクテイキング","psychological safety, team learning, risk-taking, speaking up")
add("Knowledge-Creating Crew","知識創造クルー","プロジェクトベースで集まり、知識創造活動を行う小規模チーム。野中の「自己組織化チーム」概念を発展させ、多様な専門性を持つメンバーが自律的に知識創造プロセスを推進する組織単位。","プロジェクトベースの知識創造チーム。","知識創造論",2008,"organizational","自律的知識創造の組織単位",["野中郁次郎","竹内弘高"],["Nonaka & Takeuchi (1995)"],"","知識創造チーム,自己組織化,プロジェクト","knowledge-creating crew, self-organizing, project-based")
add("Contextual Ambidexterity","文脈的両利き","構造的分離ではなく、個人が自らの判断で探索と活用のバランスを取る能力を組織文化・制度設計によって促進するアプローチ。Gibson & Birkinshaw（2004年）がストレッチ、規律、サポート、信頼の4要素で概念化。","個人レベルの探索-活用バランスを文脈で促進。","動的能力論",2004,"organizational","組織文脈による個人的両利きの促進",["Cristina Gibson","Julian Birkinshaw"],["Gibson & Birkinshaw (2004) The Antecedents, Consequences, and Mediating Role of Organizational Ambidexterity"],"structural ambidexterity","文脈的両利き,個人的バランス,組織文化","contextual ambidexterity, individual balance, organizational culture")
add("Knowledge Recombination","知識の再結合","既存の知識要素を新しい方法で組み合わせることによって新知識・イノベーションが生まれるメカニズム。Schumpeterの「新結合」概念を知識レベルに適用し、知識の多様性と結合能力がイノベーションを規定する。","既存知識の新結合によるイノベーション創出。","知識マネジメント",2003,"organizational","既存知識の創造的組み合わせ",["Lee Fleming","Andrew Hargadon"],["Fleming (2001) Recombinant Uncertainty in Technological Search"],"","知識再結合,新結合,創造的組み合わせ","knowledge recombination, new combination, creative recombination")
add("Organizational Learning Curve","組織学習曲線","組織全体の学習プロセスを累積経験と成果の関係として定量化したもの。個人の学習曲線を超えた組織レベルの学習ダイナミクス（ルーティン化、知識の制度化、人員変動の影響等）を分析する。","組織レベルの累積的学習の定量的分析。","組織学習",1990,"organizational","組織全体の累積的学習",["Linda Argote"],["Argote (1999) Organizational Learning: Creating, Retaining and Transferring Knowledge"],"","組織学習曲線,累積学習,ルーティン化","organizational learning curve, cumulative learning, routinization")
add("Vicarious Learning","代理学習","他組織の経験（成功・失敗）を間接的に観察して学習するプロセス。直接経験のコストとリスクを回避しつつ、他者の経験から教訓を抽出する効率的な学習形態。","他組織の経験からの間接的学習。","組織学習",1988,"organizational","他者の経験の間接的活用",["Huber","Kim & Miner"],["Huber (1991) Organizational Learning"],"","代理学習,間接学習,他者経験","vicarious learning, indirect learning, other's experience, observation")
add("Superstitious Learning","迷信的学習","組織が因果関係を誤認して「間違った教訓」を学習するプロセス。成功の原因を誤帰属し、効果のない行動を強化したり、偶然の成功を能力と誤認する学習の病理。","因果関係の誤認による誤った学習。","組織学習",1988,"organizational","因果関係の誤認と強化",["James March","Daniel Levinthal"],["Levinthal & March (1993) The Myopia of Learning"],"","迷信的学習,誤帰属,学習の病理","superstitious learning, misattribution, learning pathology")
add("Interorganizational Learning","組織間学習","アライアンス、サプライチェーン、コンソーシアム等の組織間関係を通じた相互的な学習プロセス。知識の相互移転、共同知識創造、制度的学習等の多様な形態がある。","組織間関係を通じた相互的な学習プロセス。","組織学習",1998,"organizational","組織間の相互的知識交換",["Andrew Inkpen","Anoop Madhok"],["Inkpen & Tsang (2005) Social Capital, Networks, and Knowledge Transfer"],"","組織間学習,相互学習,アライアンス学習","interorganizational learning, mutual learning, alliance learning")
add("Mindful Learning in Organizations","組織におけるマインドフル学習","Langer（1989年）のマインドフルネス概念を組織学習に適用し、ルーティン化された無意識的行動（マインドレス）から脱却して、環境の変化に注意深く対応する学習形態。Weick & Sutcliffe（2001年）がHRO（高信頼性組織）の文脈で発展。","注意深い状況認識に基づく適応的学習。","組織学習",2001,"organizational","注意深い状況認識と適応",["Karl Weick","Kathleen Sutcliffe"],["Weick & Sutcliffe (2001) Managing the Unexpected"],"","マインドフル学習,高信頼性組織,注意深さ","mindful learning, HRO, mindfulness, situational awareness")
add("Knowledge Management Maturity Model","知識管理成熟度モデル","組織の知識管理能力を段階的に評価するフレームワーク。初期段階（ad hoc）→反復段階→定義段階→管理段階→最適化段階の5段階で、KM実践の制度化と高度化の現状を診断する。","知識管理能力の段階的評価と改善ガイド。","知識マネジメント",2003,"organizational","KM能力の段階的評価",["Karl Wiig","APQC"],["APQC KM Maturity Model"],"","KM成熟度,段階的評価,能力改善","KM maturity, staged assessment, capability improvement")
add("Knowledge Visualization","知識の可視化","抽象的な知識・概念・関係を視覚的表現（マインドマップ、コンセプトマップ、知識マップ、インフォグラフィック等）を通じてコミュニケーション可能にする手法群。知識移転と理解の促進を目的とする。","知識の視覚的表現による理解とコミュニケーションの促進。","知識マネジメント",2004,"organizational","視覚的表現による知識伝達",["Martin Eppler","Remo Burkhard"],["Eppler & Burkhard (2007) Visual Representations in Knowledge Management"],"","知識可視化,マインドマップ,コンセプトマップ","knowledge visualization, mind map, concept map, visual representation")
add("Distributed Cognition","分散認知","認知プロセスが個人の頭脳内だけでなく、他者、ツール、環境に分散して存在するという認知科学の枠組み。Hutchins（1995年）が航空操縦室を例に概念化し、チームの知識活動をシステムレベルで分析する基盤を提供。","認知プロセスの人間-環境-ツール間の分散。","組織学習",1995,"organizational","認知の社会的・物質的分散",["Edwin Hutchins"],["Hutchins (1995) Cognition in the Wild"],"","分散認知,認知の分散,チーム認知","distributed cognition, cognitive distribution, team cognition")
add("Knowledge Worker Autonomy","知識労働者の自律性","知識労働者が仕事の内容、方法、時間、場所について裁量を持つ程度。自律性が知識創造、創造的問題解決、モチベーションを促進するメカニズムと、組織的調整との緊張の分析。","知識労働者の自律性がイノベーションを促進するメカニズム。","知識マネジメント",2000,"organizational","自律性による創造的活動の促進",["Teresa Amabile"],["Amabile (1998) How to Kill Creativity"],"","知識労働者自律性,裁量,創造性","knowledge worker autonomy, discretion, creativity, motivation")
add("Knowledge Entropy","知識エントロピー","組織の知識基盤が時間経過・人員変動・環境変化等により劣化・散逸する傾向。熱力学のエントロピー概念を知識管理に適用し、知識の秩序維持に必要なエネルギー投入（知識管理活動）の必要性を理論化。","知識基盤の自然な劣化傾向とその管理。","知識マネジメント",2005,"organizational","知識の自然劣化と維持コスト",["Max Boisot"],["Boisot (1998) Knowledge Assets"],"","知識エントロピー,知識劣化,維持コスト","knowledge entropy, knowledge degradation, maintenance cost")
add("Knowledge Supply Chain","知識サプライチェーン","知識の生成（大学・研究機関）→加工（コンサルティング・仲介機関）→配達（トレーニング・メディア）→消費（企業・実務者）の一連のフローをサプライチェーン・アナロジーで分析する枠組み。","知識の生成から消費までのフロー分析。","知識マネジメント",2003,"organizational","知識フローのバリューチェーン分析",["Andrew Hargadon"],["Holsapple & Singh (2001) The Knowledge Chain Model"],"","知識サプライチェーン,知識フロー,バリューチェーン","knowledge supply chain, knowledge flow, value chain")
add("Situated Learning Theory","状況的学習理論","学習が特定の社会的・物理的文脈に埋め込まれて生じるという理論。Lave & Wenger（1991年）が正統的周辺参加として定式化し、学習を個人の認知的活動ではなく社会的参加のプロセスとして再定義した。","学習を社会的文脈に埋め込まれた参加プロセスとして理論化。","社会的学習理論",1991,"organizational","社会的文脈への参加としての学習",["Jean Lave","Etienne Wenger"],["Lave & Wenger (1991) Situated Learning"],"","状況的学習,正統的周辺参加,社会的参加","situated learning, legitimate peripheral participation, social participation")

output_dir = os.path.dirname(os.path.abspath(__file__))
total = len(entries)
print(f"Total know entries generated: {total}")
for batch_idx in range(0, total, 50):
    batch = entries[batch_idx:batch_idx+50]
    batch_num = batch_idx // 50 + 1
    filepath = os.path.join(output_dir, f"know_batch_{batch_num}.json")
    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(batch, f, ensure_ascii=False, indent=2)
    print(f"Written {len(batch)} to {filepath} (IDs: {batch[0]['id']} - {batch[-1]['id']})")
